// ===== CONFIG — change paths here =====
const OUTPUT_PATH = 'C:\\Users\\79818\\Downloads\\your_leads_mx.csv';
const CONCURRENCY = 40;

// ===== PROVIDER PATTERNS =====
const DIRECT = [
  { name: 'Google',     p: ['aspmx.l.google.com','googlemail.com','alt1.aspmx','alt2.aspmx','aspmx2.googlemail','aspmx3.googlemail'] },
  { name: 'Microsoft',  p: ['mail.protection.outlook.com','olc.protection.outlook.com','outlook.com'] },
  { name: 'Mimecast',   p: ['mimecast.com'] },
  { name: 'Proofpoint', p: ['pphosted.com'] },
  { name: 'Barracuda',  p: ['barracudanetworks.com'] },
  { name: 'Zoho',       p: ['zoho.com','zoho.eu'] },
  { name: 'ProtonMail', p: ['protonmail.ch'] },
  { name: 'Yahoo',      p: ['yahoodns.net'] },
];

const GATEWAYS = {
  'hornetsecurity.com':   'Hornetsecurity',
  'ppe-hosted.com':       'Proofpoint Essentials',
  'sophos.com':           'Sophos',
  'trendmicro.com':       'Trend Micro',
  'zerospam.ca':          'ZeroSpam',
  'antispameurope.com':   'Antispam Europe',
  'mtaroutes.com':        'MTA Routes',
  'mxthunder.net':        'MX Thunder',
  'mxthunder.com':        'MX Thunder',
  'iphmx.com':            'Cisco IronPort',
  'arsmtp.com':           'AR SMTP',
  'emailservice.co':      'Email Service',
  'emailservice.io':      'Email Service',
  'emailservice.cc':      'Email Service',
  'siteprotect.com':      'SiteProtect',
  'mailhop.org':          'Mailhop',
  'titanhq.com':          'TitanHQ',
  'gosecure.net':         'GoSecure',
  'esvacloud.com':        'ESVA Cloud',
  'megamailservers.com':  'Mega Mail Servers',
  'mycloudmailbox.com':   'My Cloud Mailbox',
  'ncisystems.com':       'NCI Systems',
};

// ===== HELPERS =====
function getDomain(email) {
  email = (email || '').trim().toLowerCase();
  return email.includes('@') ? email.split('@')[1] : '';
}

function classify(mxList, txt) {
  if (!mxList.length) return ['No MX', ''];
  const combined = mxList.join(' ').toLowerCase();
  for (const { name, p } of DIRECT) {
    if (p.some(x => combined.includes(x))) return [name, ''];
  }
  const parts = mxList[0].replace(/\.$/, '').split('.');
  const root = parts.slice(-2).join('.');
  const gname = GATEWAYS[root] || root;
  const hint = txt.includes('spf.protection.outlook.com') || txt.includes('onmicrosoft.com') ? 'Microsoft'
             : txt.includes('_spf.google.com') ? 'Google' : '';
  return ['Other', hint ? `${gname} (${hint})` : gname];
}

function parseCSV(text) {
  const lines = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
  function parseLine(line) {
    const res = []; let cur = ''; let q = false;
    for (let i = 0; i < line.length; i++) {
      const c = line[i];
      if (c === '"') {
        if (q && line[i+1] === '"') { cur += '"'; i++; } else q = !q;
      } else if (c === ',' && !q) { res.push(cur); cur = ''; }
      else cur += c;
    }
    res.push(cur);
    return res;
  }
  const headers = parseLine(lines[0]);
  const rows = lines.slice(1).filter(l => l.trim()).map(l => {
    const v = parseLine(l);
    const row = {};
    headers.forEach((h, i) => row[h] = (v[i] || '').trim());
    return row;
  });
  return { headers, rows };
}

function buildCSV(headers, rows) {
  const esc = v => `"${String(v || '').replace(/"/g, '""')}"`;
  return [
    headers.map(esc).join(','),
    ...rows.map(r => headers.map(h => esc(r[h])).join(','))
  ].join('\n');
}

async function fetchDNS(domain, type) {
  try {
    const r = await fetch(`https://dns.google/resolve?name=${domain}&type=${type}`);
    if (!r.ok) return null;
    return await r.json();
  } catch { return null; }
}

// ===== MAIN =====
const item = $input.first();
const binaryKey = Object.keys(item.binary || {})[0] || 'data';
const binaryItem = item.binary[binaryKey];
const base64 = typeof binaryItem === 'string' ? binaryItem : binaryItem.data;
const rawText = Buffer.from(base64, 'base64').toString('utf-8').replace(/^\uFEFF/, '');

const { headers, rows } = parseCSV(rawText);
const emailField = headers.find(h => h.trim().toLowerCase() === 'email') || headers[0];
const domains = [...new Set(rows.map(r => getDomain(r[emailField])).filter(Boolean))];

console.log(`Rows: ${rows.length} | Unique domains: ${domains.length}`);

// Concurrent DNS fetch
const results = {};
const queue = [...domains];
const workers = Array.from({ length: Math.min(CONCURRENCY, domains.length) }, async () => {
  while (queue.length) {
    const domain = queue.shift();
    const [mxData, txtData] = await Promise.all([
      fetchDNS(domain, 'MX'),
      fetchDNS(domain, 'TXT')
    ]);
    const mx = (mxData?.Answer || []).filter(a => a.type === 15)
      .map(a => a.data.split(' ').slice(1).join(' ').replace(/\.$/, '').toLowerCase());
    const txt = (txtData?.Answer || []).filter(a => a.type === 16)
      .map(a => a.data).join(' ').toLowerCase();
    results[domain] = classify(mx, txt);
  }
});
await Promise.all(workers);

// Add columns
const newHeaders = [...headers, 'mx_provider', 'mx_gateway'];
rows.forEach(row => {
  const domain = getDomain(row[emailField]);
  const [provider, gateway] = domain ? (results[domain] || ['Error', '']) : ['No email', ''];
  row['mx_provider'] = provider;
  row['mx_gateway'] = gateway;
});

// Stats log
const stats = {};
rows.forEach(r => { stats[r.mx_provider] = (stats[r.mx_provider] || 0) + 1; });
console.log('Results:', JSON.stringify(stats));

const csvOut = '\uFEFF' + buildCSV(newHeaders, rows);

return [{
  json: { outputPath: OUTPUT_PATH, rowCount: rows.length, stats },
  binary: {
    csvData: {
      data: Buffer.from(csvOut).toString('base64'),
      mimeType: 'text/csv',
      fileName: 'output_mx.csv'
    }
  }
}];
